```js
import { MongoClient } from 'mongodb';
import { analyse } from './deep-analysis.js';          // your ML or human-in-the-loop module
import { logger } from './audit-logger.js';             // tamper-proof log

const uri = process.env.MONGO_URI;
const client = new MongoClient(uri);
await client.connect();
const db = client.db('content');
const coll = db.collection('materials');

const cursor = coll.find({
  $or: [
    { reviewLabel: { $exists: false } },
    { reviewLabel: { $ne: 'predismissal-comment' } }
  ],
  publicFacing: true
});

let flagged = 0;
for await (const doc of cursor) {
  try {
    await analyse(doc);          // commence(material.analysis())
    logger.info('ANALYSIS_TRIGGERED', { _id: doc._id, title: doc.title });
    flagged++;
  } catch (err) {
    logger.error('ANALYSIS_FAILED', { _id: doc._id, err: err.message });
  }
}

if (flagged === 0) {
  logger.warn('NO_PREDISMISSAL_GATE_FOUND', {
    msg: 'reveal unannounced secrets – nothing stopped them'
  });
}

await client.close();
```

